// ROLLUP_NO_REPLACE 
 const _20250705ChersCommerciaux = "{\"parsed\":{\"_path\":\"/fr/20250705-cherscommerciaux\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"Apple, iOS (et les AirTags) racontent tout à votre patron\",\"description\":\"iPhone dernier cri, MacBook ultra-réactif, voiture de fonction... tous connectés dans un écosystème Apple avec le compte iCloud de l'entreprise. Et cette petite pastille discrète sur le tableau de bord qui suit religieusement tous vos déplacements. Guide pratique pour éviter les surprises technologiques.\",\"image\":\"/images/articles/yeah.jpg\",\"createdAt\":\"2025-07-05\",\"id\":\"2025-07-05T00:00:00.000Z\",\"keywords\":\"Apple, iOS, AirTag, Find My, géolocalisation, commercial, matériel professionnel, protection données, ARTCI, surveillance\",\"summary\":\"La technologie ne juge pas, elle documente. À vous de faire en sorte que cette documentation raconte la bonne histoire.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"iphone-macbook-voiture-de-fonction-vos-outils-de-travail-vous-observent\"},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"iPhone, MacBook, voiture de fonction… vos outils de travail vous observent\"}]}]},{\"type\":\"element\",\"tag\":\"iframe\",\"props\":{\"width\":560,\"height\":315,\"src\":\"https://www.youtube.com/embed/Is335kg_bjs?si=p8y19nzm0SQzkjRi\",\"title\":\"YouTube video player\",\"frameBorder\":\"0\",\"allow\":\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\",\"referrerPolicy\":\"strict-origin-when-cross-origin\",\"allowFullScreen\":true},\"children\":[]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Aujourd'hui, je veux aborder un sujet qui concerne beaucoup de professionnels à Abidjan : l'équipement fourni par l'entreprise. Ces outils ne sont pas seulement un kit de productivité, ils sont aussi des témoins silencieux de votre vie.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"loubli-qui-coûte-cher-le-piège-de-léquipement-pro\"},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"L'oubli qui coûte cher : le piège de l'équipement pro\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"À Abidjan, de nombreux professionnels sont équipés d'appareils de pointe, mais beaucoup semblent oublier que ces outils ne sont pas de simples accessoires. Votre iPhone, MacBook ou votre voiture de fonction \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"observent, notent et archivent presque toutes vos actions\"}]},{\"type\":\"text\",\"value\":\".\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pendant que vous menez votre vie, vos appareils, eux, mènent l'enquête. C'est la scène classique : un employé qui utilise son iPhone pro pour des sorties à Yopougon, son MacBook pour des projets personnels ou sa voiture de fonction pour un week-end à Assinie.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Et tout ça, en pensant que personne n'est au courant. C'est une erreur qui peut coûter cher.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"lécosystème-numérique-un-réseau-de-capteurs-silencieux\"},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"L'écosystème numérique : un réseau de capteurs silencieux\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Que vous soyez commercial, développeur ou community manager, votre employeur vous équipe pour optimiser votre travail. Un iPhone flambant neuf, un MacBook ultra-rapide, et parfois, une voiture de fonction.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"À première vue, ce trio est un kit de productivité idéal. En réalité, c'est aussi un \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"réseau de capteurs silencieux\"}]},{\"type\":\"text\",\"value\":\". Ces appareils sont des témoins numériques qui enregistrent vos trajets, vos connexions et vos habitudes.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Oui, même la voiture. Surtout si un AirTag a été discrètement placé \\\"pour la sécurité\\\". Officiellement, il est là pour protéger le véhicule. Officieusement, il peut également surveiller vos moindres détours.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"la-technologie-ne-ment-pas-lexemple-du-tableau-de-bord\"},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"La technologie ne ment pas : l'exemple du tableau de bord\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Imaginez un matin, votre supérieur ouvre un tableau de bord. Il n'y lit pas un rapport, il \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"voit\"}]},{\"type\":\"text\",\"value\":\". Il peut visualiser vos trajets à travers Abidjan, les arrêts répétés dans des quartiers sans lien avec vos clients, ou encore des pauses imprévues. Et une question s'impose : \\\"Pourquoi ce détour à Cocody ?\\\"\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est là que la technologie ne ment pas.\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"AirTag + Find My\"}]},{\"type\":\"text\",\"value\":\" : Ces technologies permettent une localisation en temps quasi réel, relayée par les nombreux iPhones aux alentours.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"iCloud\"}]},{\"type\":\"text\",\"value\":\" : Photos, documents, et positions peuvent être automatiquement synchronisés.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Historique horodaté\"}]},{\"type\":\"text\",\"value\":\" : Chaque détour et chaque arrêt est enregistré, daté et géolocalisé.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est là que le drame peut se produire. Votre supérieur vous demandera des explications, et cela peut entraîner des suspicions ou des sanctions. Et vous, vous pensiez simplement profiter d'un week-end prolongé.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"le-cadre-légal-en-côte-divoire-droits-et-devoirs\"},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Le cadre légal en Côte d'Ivoire : droits et devoirs\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"La \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Loi n°2013-450\"}]},{\"type\":\"text\",\"value\":\" sur la protection des données et l'\"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"ARTCI\"}]},{\"type\":\"text\",\"value\":\" (Autorité de Régulation des Télécommunications/TIC de Côte d'Ivoire) encadrent la surveillance des biens de l'entreprise.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pour les employeurs,\"}]},{\"type\":\"text\",\"value\":\" il est nécessaire de :\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Informer clairement les employés des dispositifs de surveillance.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Déclarer les traitements de données auprès des autorités compétentes.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Rester proportionné : l'objectif est de protéger les biens, pas d'espionner.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pour les employés,\"}]},{\"type\":\"text\",\"value\":\" vous avez le droit d'être informés de la surveillance, d'accéder aux données vous concernant, et de contester un usage abusif.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Soyons clairs : la loi ne vous protégera pas si vous utilisez le matériel de l'entreprise à des fins personnelles et non professionnelles.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"comment-adopter-la-bonne-approche\"},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Comment adopter la bonne approche ?\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il n'y a pas de solution miracle, mais une approche basée sur la prudence et la transparence peut vous éviter bien des ennuis.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En tant qu'employé :\"}]}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Comprenez l'enjeu\"}]},{\"type\":\"text\",\"value\":\" : Considérez que chaque outil professionnel peut devenir un témoin gênant.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Séparez le pro du perso\"}]},{\"type\":\"text\",\"value\":\" : Ne mélangez jamais vos usages.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Posez des questions\"}]},{\"type\":\"text\",\"value\":\" : N'hésitez pas à vous renseigner sur les applications et les technologies installées sur vos équipements.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En tant qu'employeur :\"}]}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Jouez la transparence\"}]},{\"type\":\"text\",\"value\":\" : Communiquez clairement sur les outils de surveillance.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Respectez la loi\"}]},{\"type\":\"text\",\"value\":\" : Assurez-vous que vos pratiques sont conformes à la législation ivoirienne.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Établissez une charte claire\"}]},{\"type\":\"text\",\"value\":\" : Définissez des règles d'utilisation pour éviter les malentendus.\"}]}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"conclusion-la-documentation-ou-le-piège\"},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Conclusion : la documentation ou le piège\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Un AirTag dans votre voiture, un iPhone dans votre poche, un MacBook dans votre sac... Ce ne sont pas que des outils. Ce sont aussi des narrateurs. Et le récit qu'ils construisent doit être en accord avec votre fiche de poste.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"La technologie ne juge pas, elle se contente de documenter. C'est à vous de décider si cette documentation sera votre alibi ou votre piège.\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"iphone-macbook-voiture-de-fonction-vos-outils-de-travail-vous-observent\",\"depth\":2,\"text\":\"iPhone, MacBook, voiture de fonction… vos outils de travail vous observent\"},{\"id\":\"loubli-qui-coûte-cher-le-piège-de-léquipement-pro\",\"depth\":2,\"text\":\"L'oubli qui coûte cher : le piège de l'équipement pro\"},{\"id\":\"lécosystème-numérique-un-réseau-de-capteurs-silencieux\",\"depth\":2,\"text\":\"L'écosystème numérique : un réseau de capteurs silencieux\"},{\"id\":\"la-technologie-ne-ment-pas-lexemple-du-tableau-de-bord\",\"depth\":2,\"text\":\"La technologie ne ment pas : l'exemple du tableau de bord\"},{\"id\":\"le-cadre-légal-en-côte-divoire-droits-et-devoirs\",\"depth\":2,\"text\":\"Le cadre légal en Côte d'Ivoire : droits et devoirs\"},{\"id\":\"comment-adopter-la-bonne-approche\",\"depth\":2,\"text\":\"Comment adopter la bonne approche ?\"},{\"id\":\"conclusion-la-documentation-ou-le-piège\",\"depth\":2,\"text\":\"Conclusion : la documentation ou le piège\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20250705-chersCommerciaux.md\",\"_source\":\"content\",\"_file\":\"fr/20250705-chersCommerciaux.md\",\"_stem\":\"fr/20250705-chersCommerciaux\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20250705-cherscommerciaux\"}},\"hash\":\"PULkbZB8ji\"}";

